#include <stdio.h>

int main()
{
    int t;
    scanf("%d", &t);

    while (t--)
    {
        int N;
        scanf("%d", &N);

        int A[N];

        for (int i = 0; i < N; i++)
        {
            scanf("%d", &A[i]);
        }

        int small = A[0];
        int large = A[0];

        for (int i = 0; i < N; i++)
        {
            if (A[i] > large)
            {
                large = A[i];
            }

            if (A[i] < small)
            {
                small = A[i];
            }
        }

        printf("%d %d\n", small, large);
    }

    return 0;
}
